CREATE TABLE `employment_records` (
  `record_id` int NOT NULL,
  `employee_id` int DEFAULT NULL,
  `performance_score` int DEFAULT NULL,
  `monthly_income` decimal(10,2) DEFAULT NULL,
  `years_at_company` int DEFAULT NULL,
